\set ON_ERROR_STOP on
BEGIN;
SELECT count(*) AS before_total FROM sources;
ON CONFLICT (domain) DO NOTHING;
SELECT count(*) AS after_total, count(*) FILTER (WHERE is_active=false AND created_at > now() - interval '10 minutes') AS staged_batch FROM sources;
COMMIT;
\echo '### per-country staged this batch:'
SELECT country, count(*) FROM sources WHERE is_active=false AND source_type='rss' AND created_at > now() - interval '10 minutes' GROUP BY 1 ORDER BY 1;
